import android.content.Intent
import androidx.navigation.Navigation.findNavController
import androidx.core.app.ActivityOptionsCompat
import androidx.appcompat.app.AppCompatActivity
import android.net.Uri
import android.os.Bundle
import com.google.android.gms.tasks.OnCompleteListener
import java.util.*

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        if (intent != null && intent.data != null) {
            val uri = intent.data.toString()
            handleDeepLink(uri)
        }
    }

    private fun handleDeepLink(uri: String) {
        val parsedUri = Uri.parse(uri)
        val pathSegments = parsedUri.path.split("/")

        when {
            pathSegments[1] == "profile" -> {
                var id = -1
                try {
                    id = parsedUri.getQueryParameter("id")!!.toInt()
                } catch (e: Exception) {
                    Log.e("DeepLinkHandler", e.message, e)
                }

                val intent = Intent(this, ProfileActivity::class.java)
                intent.putExtra("id", id)

                val options = ActivityOptionsCompat.makeCustomAnimation(this, 0, 0).toBundle()
                startActivity(intent, options)
            }
            pathSegments[1] == "payment" -> {
                var status = ""
                try {
                    status = parsedUri.getQueryParameter("status")!!
                } catch (e: Exception) {
                    Log.e("DeepLinkHandler", e.message, e)
                }

                val intent = Intent(this, PaymentActivity::class.java)
                intent.putExtra("status", status)

                val options = ActivityOptionsCompat.makeCustomAnimation(this, 0, 0).toBundle()
                startActivity(intent, options)
            }
        }
    }
}